// In production: fetch from n8n API GET /executions?status=all&limit=500&startedAfter=<7d ago>
// or use the n8n Stats API endpoint
const workflows = [
  { name: 'User Feedback Classifier', collection: '01-user-research', executions: 47, errors: 0, avg_duration_s: 12, manual_minutes_saved_per_run: 5 },
  { name: 'Churn Risk Scorer', collection: '03-retention', executions: 7, errors: 0, avg_duration_s: 8, manual_minutes_saved_per_run: 15 },
  { name: 'AI Cost Monitor', collection: '09-engineering', executions: 7, errors: 0, avg_duration_s: 3, manual_minutes_saved_per_run: 10 },
  { name: 'LLM Prompt Regression Tester', collection: '09-engineering', executions: 12, errors: 2, avg_duration_s: 45, manual_minutes_saved_per_run: 30 },
  { name: 'Competitor Radar', collection: '06-market-intel', executions: 7, errors: 1, avg_duration_s: 22, manual_minutes_saved_per_run: 20 },
  { name: 'Dependency Deprecation Watcher', collection: '09-engineering', executions: 7, errors: 0, avg_duration_s: 18, manual_minutes_saved_per_run: 25 },
  { name: 'Bug Triage Assistant', collection: '09-engineering', executions: 23, errors: 3, avg_duration_s: 30, manual_minutes_saved_per_run: 8 },
  { name: 'Weekly Priorities Planner', collection: '10-team', executions: 1, errors: 0, avg_duration_s: 15, manual_minutes_saved_per_run: 45 },
  { name: 'Uptime SLA Reporter', collection: '09-engineering', executions: 7, errors: 0, avg_duration_s: 5, manual_minutes_saved_per_run: 20 }
];
const week = 'July 7–11, 2026';
return [{ json: { workflows, week } }];

const { workflows, week } = $input.first().json;
const total_executions = workflows.reduce((s,w) => s + w.executions, 0);
const total_errors = workflows.reduce((s,w) => s + w.errors, 0);
const pass_rate = parseFloat(((1 - total_errors/total_executions)*100).toFixed(1));
const total_minutes_saved = workflows.reduce((s,w) => s + (w.executions * w.manual_minutes_saved_per_run), 0);
const failing = workflows.filter(w => w.errors > 0).sort((a,b)=>(b.errors/b.executions)-(a.errors/a.executions));
const healthy = workflows.filter(w => w.errors === 0);
const most_active = [...workflows].sort((a,b)=>b.executions-a.executions).slice(0,3);
const highest_savings = [...workflows].sort((a,b)=>(b.executions*b.manual_minutes_saved_per_run)-(a.executions*a.manual_minutes_saved_per_run)).slice(0,3);
const by_collection = {};
workflows.forEach(w => { if(!by_collection[w.collection]) by_collection[w.collection]={runs:0,errors:0}; by_collection[w.collection].runs+=w.executions; by_collection[w.collection].errors+=w.errors; });
return [{ json: { workflows, week, metrics: { total_workflows: workflows.length, total_executions, total_errors, pass_rate, total_minutes_saved, total_hours_saved: parseFloat((total_minutes_saved/60).toFixed(1)) }, failing, healthy, most_active, highest_savings, by_collection, generated_at: new Date().toISOString() } }];

const d = $input.first().json;
const failingLines = d.failing.map(w => `  ⚠️ ${w.name} — ${w.errors}/${w.executions} runs failed (${((w.errors/w.executions)*100).toFixed(0)}% error rate)`).join('\n');
const activeLines = d.most_active.map(w => `  ${w.executions}x ${w.name}`).join('\n');
const savingsLines = d.highest_savings.map(w => `  ${w.name}: ${(w.executions*w.manual_minutes_saved_per_run/60).toFixed(1)}h saved`).join('\n');
const collLines = Object.entries(d.by_collection).map(([col,s]) => `  ${col}: ${s.runs} runs, ${s.errors} errors`).join('\n');
const report = [
  `AUTOMATION HEALTH DASHBOARD: ${d.week}`,
  `Generated: ${d.generated_at}`,
  `Workflows tracked: ${d.metrics.total_workflows} | Total runs: ${d.metrics.total_executions} | Pass rate: ${d.metrics.pass_rate}%`,
  `Time saved this week: ${d.metrics.total_hours_saved}h (${d.metrics.total_minutes_saved} minutes)`,
  ``,
  d.failing.length > 0 ? `NEEDS ATTENTION (failing workflows):` : '✅ ALL WORKFLOWS HEALTHY',
  d.failing.length > 0 ? failingLines : '',
  ``,
  `MOST ACTIVE:`,
  activeLines,
  ``,
  `HIGHEST VALUE (time saved):`,
  savingsLines,
  ``,
  `BY COLLECTION:`,
  collLines,
].filter(Boolean).join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
